// This function redirects std::cin, std::cout, and std::cerr
// to stringstreams to capture output and provide input programmatically.
// It assumes the user's solution is contained within a `main` function
// that can be called directly. In a real testing environment, 
// the user's `main` might be renamed (e.g., to `solution_main`) to avoid conflicts
// with the driver's `main` function, or the solution would be run as a separate process.
std::string run_solution_and_capture_output(const std::string& input_str) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    // Save original streambufs
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::streambuf* old_cerr = std::cerr.rdbuf();

    // Redirect cin, cout, cerr
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());
    std::cerr.rdbuf(ss_output.rdbuf()); // Capture stderr as well

    // Call the user's main function
    // Note: If compiling the driver and solution together, the solution's main
    // might need to be renamed (e.g., `solution_main`) to avoid linker errors.
    // For this context, we assume `main()` can be called or is appropriately linked.
    int return_code = main(); 

    // Restore original streambufs
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);
    std::cerr.rdbuf(old_cerr);

    return ss_output.str();
}

